         destructive_pattern!(
             "add-all-dot",
-            r"git\s+add\s+\.(?:\s|$)",
+            r"git\b.*?\badd\s+\.(?:\s|$)",
             "git add . stages everything including secrets, .env files, and build artifacts. Use 'git add <specific-files>' instead."
         ),
